import React from 'react';
import { cn } from '@/lib/utils';
import { type IconProps, type SvgProps, sizeMap } from '../../types';

export type MultipleTypeDefinitionsProps = IconProps;

const MultipleTypeDefinitionsLight: React.FC<SvgProps> = ({
  size,
  className,
  title,
  role,
  'aria-label': ariaLabel,
  'aria-hidden': ariaHidden,
}) => (
  <svg
    width={size}
    height={size}
    viewBox="0 0 16 16"
    fill="none"
    xmlns="http://www.w3.org/2000/svg"
    className={className}
    role={role}
    aria-label={ariaLabel}
    aria-hidden={ariaHidden}
  >
    {title && <title>{title}</title>}
    <g clipPath="url(#a)">
      <circle cx="5" cy="11" r="4.5" fill="#EDF3FF" stroke="#3574F0" />
      <path
        d="M10.905 12.07A5 5 0 1 0 3.93 5.095a6 6 0 0 1 6.975 6.975"
        fill="#FFF4EB"
      />
      <path
        d="M10.99 10.657A4 4 0 0 0 5.343 5.01a6 6 0 0 0-1.413.085 5 5 0 1 1 6.975 6.975 6 6 0 0 0 .085-1.413"
        fill="#E66D17"
      />
      <path
        d="M13.905 9.07A5 5 0 1 0 6.93 2.095a6 6 0 0 1 6.975 6.975"
        fill="#F2FCF3"
      />
      <path
        d="M13.99 7.657A4 4 0 0 0 8.343 2.01a6 6 0 0 0-1.413.085 5 5 0 1 1 6.975 6.975 6 6 0 0 0 .085-1.413"
        fill="#208A3C"
      />
    </g>
    <defs>
      <clipPath id="a">
        <path fill="#fff" d="M0 0H16V16H0z" />
      </clipPath>
    </defs>
  </svg>
);

const MultipleTypeDefinitionsDark: React.FC<SvgProps> = ({
  size,
  className,
  title,
  role,
  'aria-label': ariaLabel,
  'aria-hidden': ariaHidden,
}) => (
  <svg
    width={size}
    height={size}
    viewBox="0 0 16 16"
    fill="none"
    xmlns="http://www.w3.org/2000/svg"
    className={className}
    role={role}
    aria-label={ariaLabel}
    aria-hidden={ariaHidden}
  >
    {title && <title>{title}</title>}
    <g clipPath="url(#a)">
      <circle cx="5" cy="11" r="4.5" fill="#25324D" stroke="#548AF7" />
      <path
        d="M10.905 12.07A5 5 0 1 0 3.93 5.095a6 6 0 0 1 6.975 6.975"
        fill="#3D3223"
      />
      <path
        d="M10.99 10.657A4 4 0 0 0 5.343 5.01a6 6 0 0 0-1.413.085 5 5 0 1 1 6.975 6.975 6 6 0 0 0 .085-1.413"
        fill="#C77D55"
      />
      <path
        d="M13.905 9.07A5 5 0 1 0 6.93 2.095a6 6 0 0 1 6.975 6.975"
        fill="#253627"
      />
      <path
        d="M13.99 7.657A4 4 0 0 0 8.343 2.01a6 6 0 0 0-1.413.085 5 5 0 1 1 6.975 6.975 6 6 0 0 0 .085-1.413"
        fill="#57965C"
      />
    </g>
    <defs>
      <clipPath id="a">
        <path fill="#fff" d="M0 0H16V16H0z" />
      </clipPath>
    </defs>
  </svg>
);

export const MultipleTypeDefinitions: React.FC<
  MultipleTypeDefinitionsProps
> = ({
  size = 'md',
  mode = 'light',
  className,
  'aria-label': ariaLabel,
  title,
  ...props
}) => {
  const SvgComponent =
    mode === 'light'
      ? MultipleTypeDefinitionsLight
      : MultipleTypeDefinitionsDark;

  return (
    <SvgComponent
      size={sizeMap[size]}
      className={cn('inline-block flex-shrink-0', className)}
      title={title}
      role={ariaLabel ? 'img' : 'presentation'}
      aria-label={ariaLabel}
      aria-hidden={!ariaLabel}
      {...props}
    />
  );
};
